import React from 'react';
import { Link } from 'react-router-dom';
import './Hero.css';

const HERO_IMG = 'https://framerusercontent.com/images/LG47yzJKYPaE9iSMjClLZQLV0Iw.jpg';

export default function Hero() {
  return (
    <section className="hero">
      {/* Background Image */}
      <div className="hero-img-wrap">
        <img src={HERO_IMG} alt="Scarlet Design Studio" className="hero-img" />
        <div className="hero-overlay" />
      </div>

      {/* Bottom content bar */}
      <div className="hero-content container">
        {/* Bottom-left: copyright + title */}
        <div className="hero-left">
          <span className="hero-copy">© 2010 – 2025</span>
          <h1 className="hero-title">Scarlet Design Studio®</h1>
        </div>

        {/* Bottom-right: tagline */}
        <p className="hero-tagline">
          We're a cutting-edge digital design studio<br />
          dedicated to crafting bold, immersive experiences.
        </p>
      </div>
    </section>
  );
}
